#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>

#define N 100005
#define Q 1005
#define K 1000000005

int n, q, k;
int a[N], b[N];
int c[N];

int read() {
    int x = 0, f = 1;
    char ch = getchar();
    while (!isdigit(ch)) {
        if (ch == '-')
            f = -1;
        ch = getchar();
    }
    while (isdigit(ch)) {
        x = x * 10 + ch - '0';
        ch = getchar();
    }
    return x * f;
}

void write(int x) {
    if (x < 0) {
        putchar('-');
        x = -x;
    }
    if (x > 9)
        write(x / 10);
    putchar(x % 10 + '0');
}

int main() {
    n = read();
    q = read();
    k = read();
    for (int i = 1; i <= n; i++) {
        a[i] = read();
        b[i] = read();
    }
    for (int i = 1; i <= q; i++) {
        int t = read();
        int l = 0, r = n;
        while (l < r) {
            int mid = (l + r) >> 1;
            if (b[mid] + (k - b[mid]) * a[mid] <= t * k)
                l = mid + 1;
            else
                r = mid;
        }
        int ans = 0;
        for (int j = 1; j <= l - 1; j++) {
            if (a[j] == a[j + 1] || b[j] == b[j + 1])
                ans++;
        }
        write(ans);
        putchar('\n');
    }
    return 0;
}

